var knife=require("../knife"),Issue=require("../issue");module.exports={name:"id-class-no-ad",on:["attr"],filter:["id","class"],desc:["If set, values for the `id` and `class` attributes may not use the word",'"ad", "banner", or "social".',"This rule only bans those words when not adjacent to other alphanumeric",'characters. Thus words like "gradient" are still allowed.'].join("\n")},module.exports.lint=function(e,a){var n=/(^|[^a-zA-Z0-9])(ad|banner|social)(?![a-zA-Z0-9])/.exec(e.value);if(!n)return[];var r=n.index+n[1].length,s=knife.getLineColFunc(e.value,e.valueLineCol)(r);return new Issue("E010",s,{word:n[2]})};